import React from 'react';
import ProgressBar from '../components/ProgressBar';
import QuestionBox from '../components/QuestionBox';
import Options from '../components/Options';
import '../styles/global.css';  // CSS toàn cục nếu có
import { useNavigate } from 'react-router-dom';

const questions = [
  {
    question: "Bạn biết tới Duolingo từ đâu?",
    options: [
      "YouTube",
      "TV",
      "Bạn bè/gia đình",
      "Tìm kiếm Google",
      "Tin tức/báo chí/blog",
      "TikTok",
      "Facebook/Instagram",
      "Khác"
    ]
  },
  {
    question: "Câu hỏi tiếp theo?",
    options: [
      "Lựa chọn 1",
      "Lựa chọn 2",
      "Lựa chọn 3",
      "Lựa chọn 4"
    ]
  }
  // Thêm nhiều câu hỏi khác nếu cần
];

const Survey = () => {
  const navigate = useNavigate();

  const handleSubmit = () => {
    // Logic xử lý sau khi khảo sát hoàn thành
    navigate('/home');  // Chuyển hướng đến trang Home
  };

  return (
    <div>
      <h1>Khảo sát</h1>
      {/* Nội dung khảo sát */}
      <button onClick={handleSubmit}>Hoàn thành</button>
    </div>
  );
};

export default Survey;
